    *b = canonical_bits(bits_b);
}

static int cmp_signature(const void *lhs, const void *rhs) {
    const signature_t *a = (const signature_t *)lhs;
    const signature_t *b = (const signature_t *)rhs;
    if (a->a < b->a) return -1;
    if (a->a > b->a) return 1;
    if (a->b < b->b) return -1;
    if (a->b > b->b) return 1;
    if (a->seed < b->seed) return -1;
    if (a->seed > b->seed) return 1;
    return 0;
}

static uint32_t lower_bound_signature(signature_t *arr, size_t n, uint64_t a, uint64_t b) {
    size_t lo = 0;
    size_t hi = n;
    while (lo < hi) {
        size_t mid = lo + (hi - lo) / 2;
        if (arr[mid].a < a || (arr[mid].a == a && arr[mid].b < b)) {
            lo = mid + 1;
        } else {
            hi = mid;
        }
    }
    return (uint32_t)lo;
}

static void derive_states(uint32_t k0_seed, uint32_t k3_seed, uint32_t *R1, uint32_t *R2) {
    uint32_t k0 = expand(k0_seed);
    uint32_t k3 = expand(k3_seed);
    for (size_t i = 0; i < pair_count; i++) {
        R1[i] = pairs[i].L0 ^ f_function(pairs[i].R0 ^ k0);
        R2[i] = pairs[i].R4 ^ f_function(pairs[i].R3 ^ k3);
    }
}

static int recover_k1(uint32_t *seed_out, const uint32_t *R1, const uint32_t *R2) {
    for (uint32_t seed = 0; seed < MAX_KEY_SEED; seed++) {
        uint32_t key = expand(seed);
        int ok = 1;
        for (size_t i = 0; i < pair_count; i++) {
            if (f_function(R1[i] ^ key) != (pairs[i].R0 ^ R2[i])) {
                ok = 0;
                break;
            }
        }
        if (ok) {
            *seed_out = seed;
            return 1;
        }
    }
    return 0;
}

static int recover_k2(uint32_t *seed_out, const uint32_t *R1, const uint32_t *R2) {
    for (uint32_t seed = 0; seed < MAX_KEY_SEED; seed++) {
        uint32_t key = expand(seed);
        int ok = 1;
        for (size_t i = 0; i < pair_count; i++) {
            if (f_function(R2[i] ^ key) != (R1[i] ^ pairs[i].R3)) {
                ok = 0;
                break;
            }
        }
        if (ok) {
            *seed_out = seed;
            return 1;
        }
    }
    return 0;
}

static int try_candidate_outer(uint32_t k0_seed, uint32_t k3_seed, uint32_t recovered[4]) {
    uint32_t R1[NUM_PAIRS];
    uint32_t R2[NUM_PAIRS];
    derive_states(k0_seed, k3_seed, R1, R2);

    uint32_t k1_seed;
    uint32_t k2_seed;
    if (!recover_k1(&k1_seed, R1, R2)) {
        return 0;
    }
    if (!recover_k2(&k2_seed, R1, R2)) {
        return 0;
    }

    recovered[0] = k0_seed;
    recovered[1] = k1_seed;
    recovered[2] = k2_seed;
    recovered[3] = k3_seed;
    return 1;
}

static int recover_all_keys(uint32_t recovered[4]) {
    signature_t *k3_sigs = malloc(sizeof(signature_t) * MAX_KEY_SEED);
    if (!k3_sigs) {
        fprintf(stderr, "Failed to allocate signature table\n");
        return 0;
    }

    for (uint32_t seed = 0; seed < MAX_KEY_SEED; seed++) {
        compute_k3_signature(seed, &k3_sigs[seed].a, &k3_sigs[seed].b);
        k3_sigs[seed].seed = seed;
    }
    qsort(k3_sigs, MAX_KEY_SEED, sizeof(signature_t), cmp_signature);

    for (uint32_t k0_seed = 0; k0_seed < MAX_KEY_SEED; k0_seed++) {
        uint64_t a, b;
        compute_k0_signature(k0_seed, &a, &b);
        uint32_t idx = lower_bound_signature(k3_sigs, MAX_KEY_SEED, a, b);
        while (idx < MAX_KEY_SEED && k3_sigs[idx].a == a && k3_sigs[idx].b == b) {
            if (try_candidate_outer(k0_seed, k3_sigs[idx].seed, recovered)) {
                free(k3_sigs);
                return 1;
            }
            idx++;
        }
    }

    free(k3_sigs);
    return 0;
}

static int verify_known_pair(const uint32_t seeds[4], const uint32_t keys[4]) {
    uint64_t recovered_pt = decrypt_block(pairs[0].ct, keys);
    if (recovered_pt != pairs[0].pt) {
        fprintf(stderr, "Known-pair decrypt check failed\n");
        return 0;
    }

    uint64_t recovered_ct = encrypt_block(pairs[0].pt, keys);
    if (recovered_ct != pairs[0].ct) {
        fprintf(stderr, "Known-pair encrypt check failed\n");
        return 0;
    }

    for (size_t i = 0; i < pair_count; i++) {
        if (encrypt_block(pairs[i].pt, keys) != pairs[i].ct) {
            fprintf(stderr, "Full pair verification failed at pair %zu\n", i);
            return 0;
        }
    }

    printf("Recovered seeds: %05" PRIx32 " %05" PRIx32 " %05" PRIx32 " %05" PRIx32 "\n",
           seeds[0], seeds[1], seeds[2], seeds[3]);
    return 1;
}

static int decrypt_ciphertexts(const char *ciphertexts_path, const char *plaintexts_path, const uint32_t keys[4]) {
    FILE *in = fopen(ciphertexts_path, "r");
    if (!in) {
        perror("fopen ciphertexts");
        return 0;
    }
    FILE *out = fopen(plaintexts_path, "w");
    if (!out) {
        perror("fopen plaintexts");
        fclose(in);
        return 0;
    }

    uint64_t check_ct[REENCRYPT_CHECKS];
    uint64_t check_pt[REENCRYPT_CHECKS];
    size_t stored = 0;
    size_t count_in = 0;
    char line[256];

    while (fgets(line, sizeof(line), in)) {
        char *endptr = NULL;
        uint64_t ct = strtoull(line, &endptr, 10);
        if (endptr == line) {
            continue;
        }
        uint64_t pt = decrypt_block(ct, keys);
        fprintf(out, "%" PRIu64 "\n", pt);
        if (stored < REENCRYPT_CHECKS) {
            check_ct[stored] = ct;
            check_pt[stored] = pt;
            stored++;
        }
        count_in++;
    }

    fclose(in);
    fclose(out);

    FILE *verify = fopen(plaintexts_path, "r");
    if (!verify) {
        perror("reopen plaintexts");
        return 0;
    }
    size_t count_out = 0;
    while (fgets(line, sizeof(line), verify)) {
        count_out++;
    }
    fclose(verify);

    if (count_in != count_out) {
        fprintf(stderr, "Line-count mismatch: ciphertexts=%zu plaintexts=%zu\n", count_in, count_out);
        return 0;
    }

    for (size_t i = 0; i < stored; i++) {
        if (encrypt_block(check_pt[i], keys) != check_ct[i]) {
            fprintf(stderr, "Re-encryption spot check failed at index %zu\n", i);
            return 0;
        }
    }

    printf("Decrypted %zu ciphertexts to %s\n", count_out, plaintexts_path);
    return 1;
}

int main(int argc, char **argv) {
    const char *pairs_path = "/app/pairs.txt";
    const char *ciphertexts_path = "/app/ciphertexts.txt";
    const char *plaintexts_path = "/app/plaintexts.txt";

    if (argc == 4) {
        pairs_path = argv[1];
        ciphertexts_path = argv[2];
        plaintexts_path = argv[3];
    } else if (argc != 1) {
        fprintf(stderr, "Usage: %s [pairs.txt ciphertexts.txt plaintexts.txt]\n", argv[0]);
        return 1;
    }

    load_pairs(pairs_path);
    if (!relation_check()) {
        return 1;
    }

