    if (!recover_all_keys(seeds)) {
        fprintf(stderr, "Failed to recover round-key seeds\n");
        return 1;
    }

    uint32_t keys[4];
    for (int i = 0; i < 4; i++) {
        keys[i] = expand(seeds[i]);
    }

    if (!verify_known_pair(seeds, keys)) {
        return 1;
    }
    if (!decrypt_ciphertexts(ciphertexts_path, plaintexts_path, keys)) {
        return 1;
    }

    return 0;
}
